-- Step 1 
CREATE MASTER KEY ENCRYPTION BY PASSWORD = 'raziqUmfassungsweg9';
-- Step 2 
CREATE DATABASE SCOPED CREDENTIAL GoldCredential
WITH IDENTITY = 'Managed Identity';
-- Step 3
CREATE EXTERNAL DATA SOURCE GoldLayer
WITH (
    LOCATION = 'abfss://gold@<storageaccountraziq>.dfs.core.windows.net/',
    CREDENTIAL = GoldCredential
);
-- Step 4 
CREATE EXTERNAL FILE FORMAT DeltaFormat
WITH (FORMAT_TYPE = DELTA);
-- Step 5
CREATE SCHEMA sales_schema;
-- Step 6
CREATE EXTERNAL TABLE sales_schema.sales
(
    Outlet_Establishment_Year  NVARCHAR(100),
    Outlet_Location_Type    NVARCHAR(100),
    [round(sum(Item_Outlet_Sales) AS total_sales, 2)]   INT
)
WITH (
    LOCATION     = 'sales/',
    DATA_SOURCE  = GoldLayer,
    FILE_FORMAT  = DeltaFormat
);
-- Step 7 
-- Create User Credentials 
-- Register user at server level
USE sales_db;

-- Register the group at server level
CREATE LOGIN [Gold Layer Users] FROM EXTERNAL PROVIDER;

-- Map group into GoldDB
CREATE USER [Gold Layer Users] FOR LOGIN [Gold Layer Users];

-- Grant read access to all gold tables
GRANT SELECT ON SCHEMA::sales_schema TO [Gold Layer Users];
